def parse_bool(value):
    normalized = str(value).strip().lower()
    if normalized in {'1', 'true', 'yes'}:
        return True
    if normalized in {'0', 'false', 'no'}:
        return False
    raise ValueError(f'invalid boolean value: {value}')

def load(raw):
    return {'enabled': parse_bool(raw['enabled'])}

