import pytest

from src.settings import load

def test_loader_covers_enabled_bool_parser():
    assert load({'enabled': 'yes'}) == {'enabled': True}
    assert load({'enabled': 'no'}) == {'enabled': False}

def test_loader_rejects_invalid_bool_values():
    with pytest.raises(ValueError):
        load({'enabled': 'maybe'})
